// SPDX-License-Identifier: MIT
pragma solidity 0.8.34;

/// @title  Adler32
/// @notice Adler-32 checksum (RFC 1950) for zlib streams.
/// @dev    Internal-only. NMAX-aware so the inner additions can run unchecked
///         for up to 5552 bytes between modulo reductions. Per-Punk inputs are
///         600 bytes and never trip the NMAX boundary, but the algorithm is
///         written to support future mosaic encoding (`PunksPNG.sol`).
library Adler32 {
    uint256 private constant BASE = 65521;
    uint256 private constant NMAX = 5552;

    function adler32(bytes memory data) internal pure returns (uint32) {
        return adler32Slice(data, 0, data.length);
    }

    function adler32Slice(bytes memory data, uint256 offset, uint256 length)
        internal
        pure
        returns (uint32)
    {
        uint256 a = 1;
        uint256 b = 0;
        uint256 i = offset;
        uint256 end = offset + length;
        while (i < end) {
            uint256 limit = i + NMAX;
            if (limit > end) limit = end;
            unchecked {
                while (i < limit) {
                    a += uint8(data[i]);
                    b += a;
                    ++i;
                }
            }
            a %= BASE;
            b %= BASE;
        }
        return uint32((b << 16) | a);
    }
}

project/contracts/lib/Crc32.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.34;

/// @title  Crc32
/// @notice IEEE 802.3 CRC32 (poly 0xEDB88320), used by PNG chunks.
/// @dev    Table-based, internal-only. Build the 256-entry table once with
///         `buildTable()` and reuse it across many calls inside one
///         transaction. The convenience `crc32(bytes)` rebuilds the table on
///         every call.
library Crc32 {
    uint256 private constant POLY = 0xEDB88320;

    /// @dev Convenience for one-shot CRC over an entire byte array.
    function crc32(bytes memory data) internal pure returns (uint32) {
        return crc32Slice(buildTable(), data, 0, data.length);
    }

    /// @dev CRC over a memory slice using a precomputed table.
    function crc32Slice(
        uint256[256] memory table,
        bytes memory data,
        uint256 offset,
        uint256 length
    ) internal pure returns (uint32) {
        uint256 crc = 0xFFFFFFFF;
        unchecked {
            uint256 end = offset + length;
            for (uint256 i = offset; i < end; ++i) {
                uint256 b = uint8(data[i]);
                crc = (crc >> 8) ^ table[(crc ^ b) & 0xFF];
            }
        }
        return uint32(crc ^ 0xFFFFFFFF);
    }

    /// @dev Builds the 256-entry CRC32 lookup table.
    function buildTable() internal pure returns (uint256[256] memory table) {
        unchecked {
            for (uint256 i = 0; i < 256; ++i) {
                uint256 c = i;
                for (uint256 k = 0; k < 8; ++k) {
                    if (c & 1 == 1) c = POLY ^ (c >> 1);
                    else c >>= 1;
                }
                table[i] = c;
            }
        }
    }
}

